function getResponseText(response) {
  if (response.output_text) return response.output_text;
  const output = Array.isArray(response.output) ? response.output : [];
  const parts = [];
  for (const item of output) {
    for (const part of item.content || []) {
      if (typeof part.text === 'string') parts.push(part.text);
    }
  }
  return parts.join('\n').trim();
}

function parseJson(text) {
  const cleaned = String(text || '').replace(/^```(?:json)?/i, '').replace(/```$/i, '').trim();
  const candidates = [
    cleaned,
    (cleaned.match(/\{[\s\S]*\}/) || [])[0] || '',
    cleaned.replace(/[\u201C\u201D]/g, '"').replace(/[\u2018\u2019]/g, "'"),
    cleaned
      .replace(/\\(?!["\\\/bfnrtu])/g, '\\\\')
      .replace(/[\u201C\u201D]/g, '"')
      .replace(/[\u2018\u2019]/g, "'"),
  ].filter(Boolean);

  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch (error) {
      continue;
    }
  }

  return {};
}

function normalizeScore(value) {
  const num = Number(value || 0);
  if (!Number.isFinite(num) || num <= 0) return 0;
  if (num <= 1) return Math.round(num * 100);
  if (num <= 10) return Math.round(num * 10);
  return Math.max(0, Math.min(100, Math.round(num)));
}

return items.map((entry, index) => {
  const source = $('Code - Extract SEO Site Signals').all()[index]?.json || {};
  const parsed = parseJson(getResponseText(entry.json || {}));
  const paidAdsDetected = typeof parsed.paid_ads_detected === 'boolean'
    ? parsed.paid_ads_detected
    : Boolean(source.paid_ads_detected);
  const paidAdsEvidence = parsed.paid_ads_evidence || source.paid_ads_evidence || null;
  const paidAdsFitScore = normalizeScore(parsed.paid_ads_fit_score || source.paid_ads_fit_score || 0);

  return {
    json: {
